export interface RecipeMaterial {
    itemId: string;
    count: number;
}

export interface RecipeResult {
    itemId: string;
    count: number;
}

export interface Recipe {
    id: string;
    name: string;
    category: string;
    level: number;
    expReward: number;
    materials: RecipeMaterial[];
    result: RecipeResult;
    description: string;
}

export interface InventoryItem {
    id: string;
    type?: string;
}

export class CraftingSystem {
    private isInitialized: boolean = false;
    private recipes: Map<string, Recipe> = new Map();
    private unlockedRecipes: Set<string> = new Set();
    private craftingLevel: number = 1;
    private craftingExp: number = 0;
    private craftingExpToNext: number = 100;

    constructor() {
        this.isInitialized = false;
        this.craftingLevel = 1;
        this.craftingExp = 0;
        this.craftingExpToNext = 100;
    }

    async init(): Promise<void> {
        this.loadRecipes();
        this.loadPlayerProgress();
        this.isInitialized = true;
        console.log('[CraftingSystem] 合成系统初始化完成');
    }

    private loadRecipes(): void {
        this.registerRecipe({
            id: 'potion_hp_small',
            name: '小生命药水',
            category: 'potion',
            level: 1,
            expReward: 10,
            materials: [{ itemId: 'herb_green', count: 2 }],
            result: { itemId: 'potion_hp_small', count: 1 },
            description: '恢复50点生命值'
        });

        this.registerRecipe({
            id: 'potion_hp_medium',
            name: '中生命药水',
            category: 'potion',
            level: 3,
            expReward: 25,
            materials: [
                { itemId: 'herb_green', count: 3 },
                { itemId: 'herb_red', count: 1 }
            ],
            result: { itemId: 'potion_hp_medium', count: 1 },
            description: '恢复150点生命值'
        });

        this.registerRecipe({
            id: 'potion_hp_large',
            name: '大生命药水',
            category: 'potion',
            level: 5,
            expReward: 50,
            materials: [
                { itemId: 'herb_green', count: 5 },
                { itemId: 'herb_red', count: 3 },
                { itemId: 'crystal_water', count: 1 }
            ],
            result: { itemId: 'potion_hp_large', count: 1 },
            description: '恢复300点生命值'
        });

        this.registerRecipe({
            id: 'potion_mp_small',
            name: '小魔法药水',
            category: 'potion',
            level: 2,
            expReward: 15,
            materials: [{ itemId: 'herb_blue', count: 2 }],
            result: { itemId: 'potion_mp_small', count: 1 },
            description: '恢复30点魔法值'
        });

        this.registerRecipe({
            id: 'sword_iron',
            name: '铁剑',
            category: 'weapon',
            level: 3,
            expReward: 40,
            materials: [
                { itemId: 'ore_iron', count: 3 },
                { itemId: 'wood_oak', count: 1 }
            ],
            result: { itemId: 'sword_iron', count: 1 },
            description: '一把普通的铁剑，攻击力+15'
        });

        this.registerRecipe({
            id: 'sword_steel',
            name: '钢剑',
            category: 'weapon',
            level: 6,
            expReward: 80,
            materials: [
                { itemId: 'ore_iron', count: 5 },
                { itemId: 'ore_coal', count: 3 }
            ],
            result: { itemId: 'sword_steel', count: 1 },
            description: '精钢打造的剑，攻击力+25'
        });

        this.registerRecipe({
            id: 'armor_leather',
            name: '皮甲',
            category: 'armor',
            level: 2,
            expReward: 30,
            materials: [
                { itemId: 'leather_wolf', count: 3 },
                { itemId: 'thread_basic', count: 2 }
            ],
            result: { itemId: 'armor_leather', count: 1 },
            description: '轻便的皮甲，防御力+8'
        });

        this.registerRecipe({
            id: 'armor_chain',
            name: '链甲',
            category: 'armor',
            level: 5,
            expReward: 70,
            materials: [
                { itemId: 'ore_iron', count: 4 },
                { itemId: 'leather_wolf', count: 2 }
            ],
            result: { itemId: 'armor_chain', count: 1 },
            description: '坚固的链甲，防御力+18'
        });

        this.registerRecipe({
            id: 'ring_health',
            name: '生命戒指',
            category: 'accessory',
            level: 4,
            expReward: 60,
            materials: [
                { itemId: 'gem_health', count: 1 },
                { itemId: 'metal_silver', count: 2 }
            ],
            result: { itemId: 'ring_health', count: 1 },
            description: '增加20点生命上限'
        });

        this.registerRecipe({
            id: 'amulet_magic',
            name: '魔法护符',
            category: 'accessory',
            level: 5,
            expReward: 80,
            materials: [
                { itemId: 'gem_mana', count: 1 },
                { itemId: 'metal_gold', count: 1 }
            ],
            result: { itemId: 'amulet_magic', count: 1 },
            description: '增加15点魔法上限'
        });

        this.registerRecipe({
            id: 'scroll_fire',
            name: '火焰卷轴',
            category: 'scroll',
            level: 6,
            expReward: 100,
            materials: [
                { itemId: 'paper_magic', count: 2 },
                { itemId: 'essence_fire', count: 1 },
                { itemId: 'ink_magic', count: 1 }
            ],
            result: { itemId: 'scroll_fire', count: 1 },
            description: '使用时释放火球术，造成150点伤害'
        });

        this.registerRecipe({
            id: 'elixir_strength',
            name: '力量药剂',
            category: 'elixir',
            level: 8,
            expReward: 150,
            materials: [
                { itemId: 'herb_golden', count: 2 },
                { itemId: 'dragon_scale_small', count: 1 }
            ],
            result: { itemId: 'elixir_strength', count: 1 },
            description: '永久增加2点力量'
        });
    }

    private registerRecipe(recipe: Recipe): void {
        this.recipes.set(recipe.id, recipe);
    }

    unlockRecipe(recipeId: string): boolean {
        const recipe = this.recipes.get(recipeId);
        if (!recipe || this.unlockedRecipes.has(recipeId)) return false;

        this.unlockedRecipes.add(recipeId);
        const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
        win.game?.showNotification?.(`解锁配方：${recipe.name}`, 'success');
        this.saveProgress();
        return true;
    }

    craft(recipeId: string, count: number = 1): boolean {
        const recipe = this.recipes.get(recipeId);
        if (!recipe) {
            const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
            win.game?.showNotification?.('配方不存在', 'error');
            return false;
        }

        if (!this.unlockedRecipes.has(recipeId)) {
            const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
            win.game?.showNotification?.('配方未解锁', 'error');
            return false;
        }

        if (this.craftingLevel < recipe.level) {
            const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
            win.game?.showNotification?.(`合成等级不足，需要 ${recipe.level} 级`, 'error');
            return false;
        }

        const win = window as unknown as { game?: { player?: { inventory: InventoryItem[] } } };
        const player = win.game?.player;
        if (!player) return false;

        for (const material of recipe.materials) {
            const inInventory = this.countItem(player.inventory, material.itemId);
            const needed = material.count * count;

            if (inInventory < needed) {
                const win2 = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
                win2.game?.showNotification?.(`材料不足：${material.itemId}`, 'error');
                return false;
            }
        }

        for (const material of recipe.materials) {
            this.removeItem(player.inventory, material.itemId, material.count * count);
        }

        const resultItem = recipe.result;
        for (let i = 0; i < resultItem.count * count; i++) {
            player.inventory.push({ id: resultItem.itemId });
        }

        this.gainExp(recipe.expReward * count);

        const win3 = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void }; audioSystem?: { playSound?: (sound: string) => void } };
        win3.game?.showNotification?.(`成功制作 ${count} 个 ${recipe.name}`, 'success');
        win3.audioSystem?.playSound?.('craft');

        return true;
    }

    private countItem(inventory: InventoryItem[], itemId: string): number {
        return inventory.filter(item => item.id === itemId).length;
    }

    private removeItem(inventory: InventoryItem[], itemId: string, count: number): void {
        let removed = 0;
        for (let i = inventory.length - 1; i >= 0; i--) {
            if (inventory[i].id === itemId && removed < count) {
                inventory.splice(i, 1);
                removed++;
            }
        }
    }

    gainExp(amount: number): void {
        this.craftingExp += amount;

        while (this.craftingExp >= this.craftingExpToNext) {
            this.craftingExp -= this.craftingExpToNext;
            this.levelUp();
        }
    }

    private levelUp(): void {
        this.craftingLevel++;
        this.craftingExpToNext = Math.floor(this.craftingExpToNext * 1.5);

        const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void }; audioSystem?: { playSound?: (sound: string) => void } };
        win.game?.showNotification?.(`合成等级提升到 ${this.craftingLevel} 级！`, 'success');
        win.audioSystem?.playSound?.('levelUp');

        this.autoUnlockRecipes();
    }

    private autoUnlockRecipes(): void {
        for (const [id, recipe] of this.recipes) {
            if (!this.unlockedRecipes.has(id) && recipe.level <= this.craftingLevel) {
                this.unlockRecipe(id);
            }
        }
    }

    canCraft(recipeId: string): boolean {
        const recipe = this.recipes.get(recipeId);
        if (!recipe) return false;
        if (!this.unlockedRecipes.has(recipeId)) return false;
        if (this.craftingLevel < recipe.level) return false;

        const win = window as unknown as { game?: { player?: { inventory: InventoryItem[] } } };
        const player = win.game?.player;
        if (!player) return false;

        for (const material of recipe.materials) {
            if (this.countItem(player.inventory, material.itemId) < material.count) {
                return false;
            }
        }

        return true;
    }

    getRecipe(recipeId: string): Recipe | undefined {
        return this.recipes.get(recipeId);
    }

    getAllRecipes(category: string | null = null): Recipe[] {
        let recipes = Array.from(this.recipes.values());

        if (category) {
            recipes = recipes.filter(r => r.category === category);
        }

        return recipes;
    }

    getCraftableRecipes(): Recipe[] {
        return Array.from(this.unlockedRecipes)
            .map(id => this.recipes.get(id))
            .filter((recipe): recipe is Recipe => recipe !== undefined && this.canCraft(recipe.id));
    }

    getUnlockedRecipes(): Recipe[] {
        return Array.from(this.unlockedRecipes)
            .map(id => this.recipes.get(id))
            .filter((recipe): recipe is Recipe => recipe !== undefined);
    }

    getCategories(): string[] {
        const categories = new Set<string>();
        for (const recipe of this.recipes.values()) {
            categories.add(recipe.category);
        }
        return Array.from(categories);
    }

    private loadPlayerProgress(): void {
        const saved = localStorage.getItem('tavern_crafting');
        if (saved) {
            try {
                const data = JSON.parse(saved);
                this.unlockedRecipes = new Set(data.unlocked || []);
                this.craftingLevel = data.level || 1;
                this.craftingExp = data.exp || 0;
                this.craftingExpToNext = data.expToNext || 100;
            } catch (error) {
                console.error('[CraftingSystem] Failed to load crafting progress:', error);
            }
        }

        this.autoUnlockRecipes();
    }

    private saveProgress(): void {
        const data = {
            unlocked: Array.from(this.unlockedRecipes),
            level: this.craftingLevel,
            exp: this.craftingExp,
            expToNext: this.craftingExpToNext
        };
        localStorage.setItem('tavern_crafting', JSON.stringify(data));
    }
}

export default CraftingSystem;
